/**
 * Shared helpers for m3ssag1n8 grading tests.
 *
 * Provides direct OwlDB API access for test setup/teardown,
 * independent of the student's UI implementation.
 */

// OwlDB URL helpers
export const DB_URL = () =>
  `${Cypress.env("DATABASE_HOST")}${Cypress.env("DATABASE_PATH")}`;
export const AUTH_URL = () =>
  `${Cypress.env("DATABASE_HOST")}${Cypress.env("AUTH_PATH")}`;

/**
 * Get an auth token via direct API call.
 */
export function apiLogin(username: string): Cypress.Chainable<string> {
  return cy
    .request({
      method: "POST",
      url: AUTH_URL(),
      body: { username },
    })
    .then((res) => res.body.token as string);
}

/**
 * Logout via direct API call.
 */
export function apiLogout(token: string): Cypress.Chainable {
  return cy.request({
    method: "DELETE",
    url: AUTH_URL(),
    headers: { Authorization: `Bearer ${token}` },
    failOnStatusCode: false,
  });
}

/**
 * Create a workspace via direct API call.
 * Also creates the channels/ collection within it.
 */
export function apiCreateWorkspace(
  token: string,
  name: string,
  body: object = {},
): Cypress.Chainable {
  return cy
    .request({
      method: "PUT",
      url: `${DB_URL()}${encodeURIComponent(name)}`,
      headers: { Authorization: `Bearer ${token}` },
      body,
      failOnStatusCode: false,
    })
    .then(() => {
      // Create the channels collection within the workspace
      return cy.request({
        method: "PUT",
        url: `${DB_URL()}${encodeURIComponent(name)}/channels/`,
        headers: { Authorization: `Bearer ${token}` },
        failOnStatusCode: false,
      });
    });
}

/**
 * Delete a workspace via direct API call.
 */
export function apiDeleteWorkspace(
  token: string,
  name: string,
): Cypress.Chainable {
  return cy.request({
    method: "DELETE",
    url: `${DB_URL()}${encodeURIComponent(name)}`,
    headers: { Authorization: `Bearer ${token}` },
    failOnStatusCode: false,
  });
}

/**
 * Create a channel via direct API call.
 * Also creates the posts/ collection within it.
 */
export function apiCreateChannel(
  token: string,
  workspace: string,
  channel: string,
  body: object = {},
): Cypress.Chainable {
  return cy
    .request({
      method: "PUT",
      url: `${DB_URL()}${encodeURIComponent(workspace)}/channels/${encodeURIComponent(channel)}`,
      headers: { Authorization: `Bearer ${token}` },
      body,
      failOnStatusCode: false,
    })
    .then(() => {
      // Create the posts collection within the channel
      return cy.request({
        method: "PUT",
        url: `${DB_URL()}${encodeURIComponent(workspace)}/channels/${encodeURIComponent(channel)}/posts/`,
        headers: { Authorization: `Bearer ${token}` },
        failOnStatusCode: false,
      });
    });
}

/**
 * Delete a channel via direct API call.
 */
export function apiDeleteChannel(
  token: string,
  workspace: string,
  channel: string,
): Cypress.Chainable {
  return cy.request({
    method: "DELETE",
    url: `${DB_URL()}${encodeURIComponent(workspace)}/channels/${encodeURIComponent(channel)}`,
    headers: { Authorization: `Bearer ${token}` },
    failOnStatusCode: false,
  });
}

/**
 * Create a post via direct API call (POST with auto-generated name).
 * Returns the created document path.
 */
export function apiCreatePost(
  token: string,
  workspace: string,
  channel: string,
  msg: string,
  parent: string = "",
): Cypress.Chainable<string> {
  return cy
    .request({
      method: "POST",
      url: `${DB_URL()}${encodeURIComponent(workspace)}/channels/${encodeURIComponent(channel)}/posts/`,
      headers: { Authorization: `Bearer ${token}` },
      body: { msg, parent },
    })
    .then((res) => {
      // POST returns the URI of the created document
      const uri = res.body.uri || res.headers.location || "";
      // Extract the path within the database (remove db prefix)
      const dbPath = Cypress.env("DATABASE_PATH");
      if (typeof uri === "string" && uri.startsWith(dbPath)) {
        return uri.substring(dbPath.length);
      }
      return uri as string;
    });
}

/**
 * Update a post's reactions via PATCH.
 */
export function apiPatchReactions(
  token: string,
  workspace: string,
  channel: string,
  postPath: string,
  reactions: Record<string, string[]>,
): Cypress.Chainable {
  // Build the full document path
  const url = `${DB_URL()}${postPath}`;
  return cy.request({
    method: "PATCH",
    url,
    headers: { Authorization: `Bearer ${token}` },
    body: [
      {
        op: "ObjectAdd",
        path: "/reactions",
        value: reactions,
      },
    ],
    failOnStatusCode: false,
  });
}

/**
 * Overwrite a post via PUT.
 */
export function apiPutPost(
  token: string,
  postPath: string,
  body: object,
): Cypress.Chainable {
  return cy.request({
    method: "PUT",
    url: `${DB_URL()}${postPath}`,
    headers: { Authorization: `Bearer ${token}` },
    body,
    failOnStatusCode: false,
  });
}

/**
 * PUT a document with arbitrary body (for creating corrupt data).
 */
export function apiPutDocument(
  token: string,
  path: string,
  body: unknown,
): Cypress.Chainable {
  return cy.request({
    method: "PUT",
    url: `${DB_URL()}${path}`,
    headers: { Authorization: `Bearer ${token}` },
    body,
    failOnStatusCode: false,
  });
}

/**
 * Delete a document via direct API call.
 */
export function apiDeleteDocument(
  token: string,
  path: string,
): Cypress.Chainable {
  return cy.request({
    method: "DELETE",
    url: `${DB_URL()}${path}`,
    headers: { Authorization: `Bearer ${token}` },
    failOnStatusCode: false,
  });
}

/**
 * Generate a unique test name to avoid collisions between test runs.
 */
export function uniqueName(prefix: string): string {
  return `${prefix}_${Date.now()}_${Math.random().toString(36).substring(2, 8)}`;
}

/**
 * Clean up a workspace and all its contents.
 */
export function cleanupWorkspace(
  token: string,
  workspace: string,
): Cypress.Chainable {
  return apiDeleteWorkspace(token, workspace);
}

/**
 * Utility: get the position (index among siblings) of an element
 * containing the given text, for verifying ordering.
 */
export function getPostOrder(
  texts: string[],
): Cypress.Chainable<number[]> {
  const positions: number[] = [];
  const chain = cy.wrap(null);
  for (const text of texts) {
    chain.then(() => {
      return cy
        .contains(text)
        .then(($el) => {
          // Get the element's position relative to the document
          const rect = $el[0].getBoundingClientRect();
          positions.push(rect.top);
        });
    });
  }
  return chain.then(() => positions);
}

